package com.covoiturage.repository; import com.covoiturage.model.Conversation; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*; public interface ConversationRepository extends JpaRepository<Conversation,Long>{ @Query("select c from Conversation c join c.participants p1 join c.participants p2 where p1.id=:a and p2.id=:b") Optional<Conversation> findByParticipants(@Param("a") Long a,@Param("b") Long b);} 
